public NUIForm getExistingImportForm(String apname, String path, int sheetIndex) throws JSONException {
    NUIForm importForm = null;
    
    NUIForm form = AppManager.getFormPage(apname, path, sheetIndex);
    List<String> copiedUrlList = Account.getInstance(apname).getCopiedUrlList(form.getRootDomainId());
    JobScheduleHandler handler = JobScheduleHandlerFactory.getInstance(Const.JOB_IMPORT_SYNC);
    RagicAccountJobSchedule importSchedule = RagicAccountJobs.getInstance().getJobSchedule(apname, Const.JOB_IMPORT_SYNC);
    if(importSchedule != null) {
    	for(String copiedUrl: copiedUrlList) {
            String[] tmp = copiedUrl.split("/");
            path = "/" + tmp[1];
            sheetIndex = Integer.parseInt(tmp[2]);
            form = AppManager.getFormPage(apname, path, sheetIndex);
            
            JSONObject jobScheduleParam = new JSONObject();
            jobScheduleParam.put("path", path);
            jobScheduleParam.put("sheet", form.getFormName());
            String paramKey = ((ParamsJobScheduleHandler)handler).createJobScheduleParamKey(apname, Const.JOB_IMPORT_SYNC, jobScheduleParam);
            
            String param = importSchedule.getParamMap().get(paramKey);
            if(param != null) {
                importForm = form;
            	break;
            }
        }
    }
    
    return importForm;
}

